-- ============================================
-- 一、进攻战术
-- ============================================

-- （一）2~3人基础进攻配合
INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('传切配合（Give and Go）', '【战术分类】2-3人基础进攻配合\n\n【战术定义】\n传切配合是最基础的篮球进攻配合，球员传球后立即无球空切篮下，接回传球完成上篮。这是所有战术体系的底层单元，野球和职业比赛通用。\n\n【执行要点】\n1. 传球人传球出手后，不要站在原地，立即向篮下切入\n2. 切入路线分为两种：\n   · 直切：直线切向篮下，适用于防守人注意力分散时\n   · 反跑后门切（Backdoor）：先向外移动，突然向篮下反方向加速切入，适用于防守过度紧逼时\n3. 切入时要举手指引传球方向，示意队友传球\n4. 持球人观察切入队员跑位，在防守人视线盲区传球\n5. 传球时机：切入队员刚好领先防守人半个身位时传出\n\n【适用场景】\n· 人盯人防守下，防守人对传球人施压时\n· 半场阵地进攻缺乏突破点时的基础配合\n· 全场快攻中的二打一情况\n\n【注意事项】\n· 切入前要制造切入空间，避免撞到防守人\n· 传球要提前量，不能等跑到位才传\n· 切入不成功要迅速回到原位，避免堵塞内线空间', '进攻', 1, 80),

('突分配合', '【战术分类】2-3人基础进攻配合\n\n【战术定义】\n持球人运球突破吸引防守协防，在包夹形成前将球分给外线空位射手或内线顺下队友。这是破解密集防守的核心配合，也是现代篮球空间打法的基石。\n\n【执行要点】\n1. 持球人坚决突破防线，迫使防守方协防\n2. 观察协防人来源方向，判断空位队友位置\n3. 突分目标选择优先级：\n   · 首选：底角三分射手（防守协防最远的位置）\n   · 次选：弧顶三分射手\n   · 可选：顺下的内线队友\n4. 传球方式选择：\n   · 突分底角：单手快速甩传或击地传球\n   · 突分内线：口袋传球或击地传球\n   · 突分弧顶：回传或背后传球\n5. 接球人要提前移动到最有威胁的空位位置\n\n【适用场景】\n· 联防阵型下突破吸引防守\n· 对手协防积极的防守体系\n· 持球人有突破优势，防守被迫包夹\n\n【注意事项】\n· 突破时不要埋头，保持抬头观察视野\n· 不要在起跳后才找传球目标（容易失误）\n· 接球人接到球后要果断投篮，不要犹豫', '进攻', 1, 75),

('掩护配合（挡拆基础-四种基础掩护）', '【战术分类】2-3人基础进攻配合\n\n【战术定义】\n掩护（Pick）是进攻球员用身体挡住防守人，为持球队友或无球队友创造时间空间的配合。挡拆是篮球最基础也是最重要的战术单元，以下为四种基础掩护形式。\n\n【四种基础掩护】\n\n1. 侧掩护（正挡）\n   · 要领：掩护人站在防守人的侧面，双腿与肩同宽站稳\n   · 持球人从掩护一侧紧贴掩体突破\n   · 这是标准Pick（挡拆）的最基本形式\n\n2. 后掩护\n   · 要领：掩护人站在防守人的身后\n   · 无球队友利用掩护从防守人视线盲区切入\n   · 适用于无球空切接球\n\n3. 前掩护\n   · 要领：掩护人站在防守人的前面\n   · 为队友挡住防守人，创造投篮空间\n   · 适用于给射手制造空位投篮机会\n\n4. 运球手递手掩护\n   · 要领：持球人运球靠近队友，近距离手递手传球\n   · 传球的同时身体挡住队友的防守人\n   · 接球人借掩护顺势突破或投篮\n\n【注意事项】\n· 掩护人必须双腿站稳，不能移动（移动掩护违例）\n· 掩护时双手交叉护住身体（保护要害）\n· 掩护人与持球人距离要近，否则防守人可从中间挤过', '进攻', 1, 70),

('挡拆配合（Pick and Roll-四种拆法）', '【战术分类】2-3人基础进攻配合\n\n【战术定义】\n挡拆是篮球最核心的进攻战术，一个球员做掩护挡住持球队友的防守人，然后根据防守反应选择不同的"拆"法（Roll/Pop等）。NBA几乎所有进攻的起点都是挡拆。\n\n【四种拆法详解】\n\n1. 掩护人顺下（Roll）\n   · 动作：挡完之后立即转身向篮下切入\n   · 持球人将球传给顺下的大个子上篮\n   · 代表：保罗+小乔丹/卡佩拉空接体系\n   · 防守应对困难，篮下高度优势明显\n\n2. 掩护人外弹（Pop）\n   · 动作：挡完之后向三分线外弹开\n   · 持球人吸引防守后传给外弹队友投三分\n   · 代表：库里+格林挡拆外弹\n   · 要求挡拆人有一定远投能力\n\n3. 掩护人横切\n   · 动作：挡完之后横向跑动到中距离区域\n   · 持球人分球给横切队友中投\n   · 适用于中距离投篮有把握的情况\n\n4. 掩护人卷切\n   · 动作：挡完之后绕掩护折返跑向篮下接球\n   · 利用多次绕桩跑动打乱防守\n   · 适用于灵活的机动型内线\n\n【注意事项】\n· 持球人和掩护人要阅读防守，根据防守选择正确拆法\n· 如果防守换防：利用错位单打\n· 如果防守沉退（Drop）：持球人直接跳投\n· 如果防守延误（Hedge）：掩护人快速拆开', '进攻', 1, 90),

('策应高低位配合（High-Low）', '【战术分类】2-3人基础进攻配合\n\n【战术定义】\n战术定义：高位中锋（罚球线附近）持球策应组织进攻，低位内线在篮下要位接球单打。利用高位和低位的传球配合撕裂防守。这是拥有双塔球队的经典战术。\n\n【执行分为两种】\n\n1. 高位吊低位\n   · 高位中锋持球面向篮筐\n   · 将球从防守人头顶吊入内线\n   · 低位队友接球直接单打\n   · 高位中锋同时做好接回传球的准备\n\n2. 低位回传高位\n   · 低位队友接球后被包夹\n   · 回传给罚球线附近的高位中锋\n   · 高位中锋接球后中距离投篮\n   · 或高位再次传导球到另一侧\n\n【战术要点】\n· 高位中锋需要较好的传球视野和中投能力\n· 低位球员需要扎实的背身单打技术\n· 两人的移动要保持同步，避免站位重叠\n· 其他三人拉开空间，给内线创造1v1机会\n\n【适用场景】\n· 拥有两名优秀大个子球员\n· 面对联防时的破局手段\n· 内线有明显对位优势时', '进攻', 1, 60),

('交叉换位配合', '【战术分类】2-3人基础进攻配合\n\n【战术定义】\n两名无球队员在罚球线或侧翼区域互相交叉跑动，利用跑动中的相互掩护和换位，甩开各自防守人获得接球空位。\n\n【执行要点】\n1. 两名无球队员面对面或侧对跑动\n2. 在交叉点互相擦肩而过\n3. 各自的防守人容易在交叉点撞到一起或被挡住\n4. 交叉后两人分别向相反方向拉开\n5. 持球人观察谁获得了空位，及时传球\n\n【变种】\n· 高交叉：两名外线在弧顶交叉\n· 低交叉：内线和外线在底线附近交叉\n· 双掩护交叉：先设掩护再交叉跑动\n\n【注意事项】\n· 交叉时两人身体要贴近，增强掩护效果\n· 跑动要突然加速，打防守一个措手不及\n· 交叉后拉开幅度要够大，创造传球角度', '进攻', 1, 45),

('空切系列战术', '【战术分类】2-3人基础进攻配合\n\n【战术定义】\n空切是无球队员通过跑动切入篮下接球得分的进攻方式，是所有战术体系中最灵活多变的得分手段。\n\n【四种主要空切方式】\n\n1. 斜线斜切\n   · 从侧翼45度斜向切入篮下\n   · 利用45度角方向切入，路线最短\n   · 接球后可直接上篮\n\n2. 底线溜切\n   · 沿底线从篮筐一侧跑到另一侧\n   · 利用篮下队友的身体做天然掩护\n   · 在防守人视线盲区接球\n\n3. 高位下顺\n   · 从高位罚球线附近向篮下切入\n   · 通常在挡拆掩护后顺势下顺\n   · 利用挡拆吸引防守后的空间\n\n4. 弱侧穿插\n   · 从球的弱侧（远离球的一侧）切入\n   · 利用防守注意力在球侧的漏洞\n   · 突然插到篮下空位接球\n\n【注意事项】\n· 空切时要阅读防守，选择防守人看不到的路线\n· 切入时机非常关键，太早太晚都会错过传球窗口\n· 切入时举手示意，让持球人明确传球目标', '进攻', 1, 55),

('假掩护（Fake Screen）', '【战术分类】2-3人基础进攻配合\n\n【战术定义】\n进攻球员假装上前做掩护（挡拆），但在即将接触防守人时突然改变方向反跑空切篮下，利用防守人准备应对挡拆的心理惯性获得空位。\n\n【执行要点】\n1. 掩护人做出标准的掩护准备动作：向持球人方向移动\n2. 防守人本能准备换防或绕掩护\n3. 掩护人在即将到达掩护位置的瞬间突然反跑\n4. 防守人措手不及，留下篮下巨大空当\n5. 持球人及时传球给反跑的队友完成空接或上篮\n\n【适用场景】\n· 防守方热衷于换防（Switch）时效果最好\n· 对方内线习惯性积极延误时\n· 关键球时刻的奇袭战术\n\n【注意事项】\n· 假掩护的动作要逼真，否则防守人不会上当\n· 反跑时机决定成败，过早过晚都会失败\n· 持球人要有传球意识和能力', '进攻', 1, 50);

-- （二）快攻战术
INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('长传快攻（一传快攻）', '【战术分类】快攻战术\n\n【战术定义】\n篮板手拿到篮板后，不落地或落地后立即用单手肩上传球方式，远距离长传给已经快下的前场球员直接上篮。这是最快速度的守转攻方式。\n\n【执行要点】\n1. 后场篮板保护：中锋或篮板手抢到防守篮板\n2. 一传出手：抢到篮板后第一时间寻找前场快下队友\n3. 传球方式：棒球式单手肩上传球（远距离最有效）\n4. 快下人：至少1-2名球员在投篮出手瞬间就已启动向前场冲刺\n5. 接球后直接攻击篮筐，不给防守退防时间\n\n【战术要求】\n· 篮板手要有出色的长传能力\n· 快下球员速度和弹跳要好\n· 两人之间要有默契的传接配合\n\n【代表】\n· NBA乐福长传詹姆斯快攻经典连线\n· FIBA比赛中后卫常用长传发动快攻', '进攻', 1, 65),

('短传推进快攻（三线快攻）', '【战术分类】快攻战术\n\n【战术定义】\n后卫获得篮板后，通过连续的短传配合逐步推进到前场，3名球员分为左路、中路、右路三条线路同时推进，利用人数优势和空间宽度完成进攻。\n\n【执行要点】\n1. 落位：3人分别跑左路、中路（持球人）、右路三线\n2. 中路持球人控球推进，观察左右两翼跑位\n3. 传球节奏：球在中路和中路-边路之间快速传递\n4. 每传一次球防守阵型就被拉扯一次\n5. 最终选择：中路直接攻筐 / 分边路投篮 / 传给跟上的拖车球员\n\n【战术优势】\n· 三线拉开最大宽度，防守难以覆盖\n· 传球推进比运球推进更快\n· 可根据防守反应灵活选择终结方式\n\n【注意事项】\n· 三线间距要保持合理（约5-7米）\n· 持球人不要过早收球，保持突破威胁\n· 最后一名球员注意拖车跟进补篮', '进攻', 1, 60),

('运球突破快攻', '【战术分类】快攻战术\n\n【战术定义】\n后卫或前锋抢到篮板后，利用个人运球能力单人快速带球过前场，利用防守未能及时退防的时间差，直接突破上篮得分。\n\n【执行要点】\n1. 获得球权后立即观察前场防守情况\n2. 如果前方只有1-2名防守人，果断运球加速\n3. 利用速度优势强行突破\n4. 面对单人防守可选择直接攻筐\n5. 如果遭遇多人协防则转为分球\n\n【适用场景】\n· 对方投篮后防守退防不及时\n· 后卫有速度优势（韦斯特布鲁克/福克斯类型）\n· 比赛快节奏阶段\n\n【注意事项】\n· 快攻中注意控制节奏，不要冲过头\n· 随时准备变向避开防守\n· 如果机会不好要及时减速转为阵地', '进攻', 1, 55),

('边线快攻与抢发底线球快攻', '【战术分类】快攻战术\n\n【战术定义】\n分为两种：1）抢断后沿边线高速推进；2）对方进球后不等防守落位，快速发底线球发动突袭快攻。\n\n【边线快攻执行要点】\n1. 抢断后球在边线附近\n2. 持球人沿边线快速推进\n3. 其他队友沿另一侧边线跟进\n4. 利用边线作为天然边界减少防守角度\n\n【抢发底线球快攻】\n1. 对方投篮命中后\n2. 发底线球的球员立即快速拿球发球\n3. 不等待内线球员，找快下的后卫\n4. 趁防守方还在庆祝或反应的一两秒\n5. 长传或短传快速推进前场\n6. 在防守完全落位前完成进攻\n\n【注意事项】\n· 抢发底线球需要全队的快速反应意识\n· 发球人要有优秀的判断力和传球能力\n· 不适用于比分领先需要消耗时间的情况', '进攻', 1, 45),

('全场上篮反击与二次篮板快攻', '【战术分类】快攻战术\n\n【战术定义】\n前场抢到进攻篮板后，利用防守方还在保护篮板的状态，不等队友落位直接在篮下二次进攻得分，或在对方投篮不中后快速发动反击。\n\n【执行要点-全场上篮反击】\n1. 防守篮板或抢断后\n2. 全队5人全部向对方半场冲刺\n3. 利用人数优势（可能形成5打4或5打3）\n4. 快速传导球找到最空位投篮点\n5. 通常在5-7秒内完成进攻\n\n【执行要点-二次篮板快攻】\n1. 进攻篮板被前场球员抢到\n2. 防守方还没来得及调整防守位置\n3. 抢到篮板的球员直接在篮下二次进攻\n4. 如果防守收缩回来，立即传给外线重新组织\n\n【战术效果】\n· 二次篮板得分对对方士气打击极大\n· 快攻反击得分效率最高\n· 适合体能好的年轻球队', '进攻', 1, 50);

-- （三）全队阵地进攻战术
-- 1.常规落位阵型
INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('1-3-1进攻落位（专破2-3联防）', '【战术分类】全队阵地进攻-落位阵型\n\n【战术定义】\n1名球员在弧顶组织，3名球员在罚球线附近一字排开，1名球员在底线游弋。这种站位专门针对2-3联防的薄弱环节设计，利用罚球线中轴和底线两个关键位置撕裂联防。\n\n【站位详解】\n· 弧顶（1人）：控球后卫，负责组织调度\n· 罚球线（1人）：最重要策应点，接球后面框可投篮可传球\n· 两翼45度（2人）：提供外线投射威胁\n· 底线（1人）：不断移动，寻找联防空隙\n\n【攻击策略】\n1. 弧顶传球给罚球线策应点\n2. 罚球线球员面筐，吸引防守收缩\n3. 观察底线球员跑位和两翼队友\n4. 防守一旦收缩就分外线，防守外扩就传底线\n5. 底线球员沿底线左右移动，配合两翼交叉换位\n\n【战术优势】\n· 罚球线是中轴，天然克制2-3联防\n· 高低位结合，攻防两端都有威胁\n· 底线移动可以创造大量空切机会', '进攻', 1, 55),

('2-1-2进攻落位（专破3-2联防）', '【战术分类】全队阵地进攻-落位阵型\n\n【战术定义】\n2人在弧顶两侧，1人在罚球线，2人在底角或低位，形成"两外一内两底"的结构，专门针对3-2联防的篮下空虚弱点。\n\n【站位详解】\n· 弧顶左右（2人）：外线投射威胁\n· 罚球线（1人）：承接转移球的中转站\n· 底角和低位（2人）：攻击篮下弱点的关键位置\n\n【攻击策略】\n1. 弧顶两人快速左右转移球调动防守\n2. 罚球线球员提上接球，吸引防守注意力\n3. 低位或底角球员寻找篮下空隙\n4. 利用3-2联防篮下防守薄弱的特点\n5. 直接高吊篮下或底角突破\n\n【战术优势】\n· 直接攻击3-2联防的阿喀琉斯之踵——篮下\n· 低位双人配置给篮下持续施压\n· 外线与内线结合，攻防多样', '进攻', 1, 50),

('1-2-2进攻落位（通用阵地）', '【战术分类】全队阵地进攻-落位阵型\n\n【战术定义】\n1人在弧顶组织，2人在两翼45度，2人在底线底角区域。这是最通用的阵地进攻落位，非对称结构但空间利用充分，适合多种战术发起。\n\n【站位详解】\n· 弧顶（1人）：组织后卫，战术发起点\n· 两翼45度（2人）：第一接球点，可投射可突破\n· 底线和底角（2人）：空间拉开者，也是空切目标\n\n【战术发起】\n1. 弧顶传给一侧45度队友\n2. 同侧底线球员上提做掩护\n3. 形成局部2v2挡拆攻防\n4. 弱侧两名球员做好接球准备\n5. 根据防守反应选择不同攻击方向\n\n【战术优势】\n· 非对称落位让防守难以预判\n· 强侧集中3人打局部配合\n· 弱侧保留投射威胁', '进攻', 1, 45),

('2-3外线落位阵型', '【战术分类】全队阵地进攻-落位阵型\n\n【战术定义】\n2人在弧顶附近（含组织后卫），3人分布在两翼和底角外线。这是强调外线投射和空间的现代化落位阵型，类似于勇士五小体系的空间最大化理念。\n\n【站位详解】\n· 弧顶（2人）：控球后卫+第二组织点\n· 两翼45度（1人）：侧翼射手\n· 底角两侧（2人）：空间最重要的位置\n\n【战术思路】\n1. 全员外线拉开，最大化内线空间\n2. 弧顶双人掩护或挡拆发起\n3. 底角球员保持在防守人最难协防的位置\n4. 突破后底角是最佳突分目标\n5. 5人全部有三分威胁，防守不敢收缩\n\n【战术优势】\n· 空间利用率最大化\n· 每个位置都有投射威胁\n· 适合突破能力强的后卫\n· 现代篮球标配阵型', '进攻', 1, 50);

-- 2.全球经典体系战术
INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('三角进攻（Triangle Offense）', '【战术分类】全队阵地进攻-经典体系\n【代表球队】芝加哥公牛（乔丹时代）、洛杉矶湖人（科比时代）\n【教练】菲尔·杰克逊\n\n【战术定义】\n一侧形成3人三角形站位（强侧），弱侧两人拉开空间。通过不断的传球、空切、低位单打和反跑切后门，从多个点发起进攻，不依赖单一持球组织者。这是NBA历史上获得总冠军最多的战术体系（11冠）。\n\n【三角站位构成】\n· 强侧3人：\n  1. 低位（内线球员）：背筐要位\n  2. 侧翼（得分后卫/小前锋）：在低位球员的同侧外线\n  3. 弧顶延伸（组织后卫/小前锋）：传完球后切入三角区域\n· 弱侧2人：\n  1. 一名在弱侧底角\n  2. 一名在弱侧45度或弧顶\n\n【五大进攻选项】\n1. 低位单打：球给低位，其余人拉开1v1\n2. 反跑后门（Backdoor）：防守紧逼时突然空切篮下\n3. 手递手挡拆：两名三角内球员配合\n4. 弱侧空切：利用防守注意力在强侧\n5. 高位策应：传给高位球员面筐组织\n\n【战术核心原则】\n· 球不停滞，人不停跑\n· 阅读防守后自主决策（不是固定套路）\n· 5个人都是进攻威胁点\n· 强侧的3人必须能传、能投、能突\n\n【适用球队】\n· 拥有全能型得分手（乔丹/科比）\n· 内线有策应能力（加索尔/罗德曼）\n· 全员高球商，能独立阅读防守', '进攻', 1, 85),

('普林斯顿战术（Princeton Offense）', '【战术分类】全队阵地进攻-经典体系\n【代表球队】萨克拉门托国王（韦伯/毕比时代）、普林斯顿大学\n【教练】皮特·卡里尔\n\n【战术定义】\n全员不停无球跑动、反跑空切、高低位策应，所有5名球员都能传球、跑动和投篮，没有固定的单打点。篮球运动的"全攻全守"理念——每个人都是平等的进攻参与者。\n\n【四大核心要素】\n\n1. 高位策应（核心标志）\n   · 中锋站在罚球线以上位置\n   · 面筐持球，观察全场跑动\n   · 拥有良好传球视野和中投能力\n   · 是整个进攻体系的中枢\n\n2. 反跑空切（标志性得分方式）\n   · 球员不断跑向篮下\n   · 如果被防守紧逼则突然反跑切后门\n   · 高位中锋立即传球\n   · 大量轻松上篮得分\n\n3. 人人能传\n   · 不依赖单一组织者\n   · 每个人接到球后都可以策应、突破、投篮\n   · 传球比运球更重要\n\n4. 连续空切循环\n   · 一次空切不成立即拉出\n   · 另一名球员紧接着切入\n   · 形成无限循环的跑动\n\n【战术效果】\n· 防守极度疲惫（不停追人跑）\n· 经常出现大量空位上篮\n· 难以布置针对性防守\n\n【适用球队】\n· 球员平均球商高\n· 大个子有传球和中投能力\n· 不依赖超级巨星单打', '进攻', 1, 75),

('UCLA战术（UCLA Cut）', '【战术分类】全队阵地进攻-经典体系\n【代表球队】UCLA大学（约翰·伍登执教时期）、NBA马刺\n【教练】约翰·伍登\n\n【战术定义】\n后卫传球给高位内线后，借内线的高位掩护从弧顶绕向篮下空切接回传球上篮。这是大学篮球史上最成功的战术之一，UCLA凭借此战术拿下10次NCAA冠军。马刺队将其融入NBA体系取得巨大成功。\n\n【标准执行步骤】\n1. 控球后卫弧顶持球\n2. 将球传给站在罚球线以上的高位中锋\n3. 后卫传球后立即启动空切\n4. 从高位中锋身旁绕过，利用中锋身体做掩护\n5. 切入篮下，接中锋的回传球\n6. 在篮下直接上篮或面对补防分球\n\n【战术变种】\n· UCLA-外弹：空切后卫被防住，转为外线接球跳投\n· UCLA-顺下：中锋传完球后顺势向篮下切入\n· UCLA-反跑：如果后卫被严防，改为反跑空切\n\n【战术优势】\n· 执行简单，训练成本低\n· 一次掩护创造多重威胁\n· 可以作为连续进攻的起手式\n\n【注意事项】\n· 高位中锋的掩护质量决定战术成败\n· 后卫切入要贴近掩护人\n· 中锋传球时机要恰到好处', '进攻', 1, 65),

('DDM运球驱动进攻（Dribble Drive Motion）', '【战术分类】全队阵地进攻-经典体系\n【代表球队】肯塔基大学、孟菲斯大学、部分NBA球队\n【教练】约翰·卡利帕里\n\n【战术定义】\n全员拉开空间到三分线外，后卫持球持续突破攻筐。如果防守协防，立即分球给外线空位三分射手；如果不协防，则直接上篮得分。将"突破→协防→分球"做到极致。\n\n【核心战术逻辑】\n1. 空间最大化：4人拉开到三分线和底角\n2. 持球人选择一侧突破\n3. 防守反应决定进攻结局：\n   · 无人协防→直接上篮\n   · 有人协防→分给协防人原本防守的队友投三分\n4. 持球人需要极强的突破能力\n5. 其他4人需要有稳定的三分投射\n\n【战术优势】\n· 战术简单易执行\n· 对防守杀伤力极大（要么给两分要么给三分）\n· 不需要复杂的战术跑动\n· 适合速度快、突破好的球队\n\n【战术劣势】\n· 依赖持球人的突破能力\n· 三分不准时容易被针对性防守\n· 缺乏低位和中距离攻击手段\n\n【适用球队】\n· 拥有顶级突破型后卫\n· 配置4名稳定三分射手\n· 追求效率和空间的现代球队', '进攻', 1, 60),

('Flex伸缩折区进攻', '【战术分类】全队阵地进攻-经典体系\n【代表球队】犹他爵士（马龙/斯托克顿时代）、波士顿凯尔特人\n\n【战术定义】\n通过底线交叉掩护和连续无球挡拆的循环轮转，球员不断绕桩跑动寻找空位。一轮跑完如果没有机会，自动开启下一轮跑位，形成无限循环的连续进攻。\n\n【标准执行流程】\n1. 初始落位：4外1内或3外2内\n2. 底线交叉：底线两名球员互相做掩护后交叉跑位\n3. 弧顶传导：球从一侧转移到另一侧\n4. 无球挡拆：强侧球员为弱侧切入球员做无球掩护\n5. 运动员绕掩护接球\n6. 如果没有投篮机会，重新落位开启下一循环\n\n【战术特点】\n· 循环性：一轮结束自动进入下一轮\n· 连续性：不需要叫暂停重新布置\n· 全员参与：每个球员都要会掩护和跑位\n· 无固定终点：哪个点出机会哪个点打\n\n【适用场景】\n· 对手防守纪律性好但移动速度慢\n· 球队缺乏超级巨星单打点\n· 需要耐心传导消耗防守', '进攻', 1, 55),

('跑轰战术（Run and Gun）', '【战术分类】全队阵地进攻-经典体系\n【代表球队】菲尼克斯太阳（纳什/斯塔德迈尔时代）\n【教练】迈克·德安东尼\n\n【战术定义】\n极致提速：拿到篮板或抢断后立即全速推进，7秒内完成进攻。大量使用追身三分、快攻上篮和挡拆后快速出手，完全放弃慢节奏的阵地进攻。不计较防守，只追求比对手得更多分。\n\n【七大核心原则】\n1. 7秒进攻法则：从获得球权到出手不超过7秒\n2. 追身三分：快攻中不等队友落位直接投三分\n3. 快发底线球：对方进球后不等防守落位立即发球\n4. 全场全速：每个人拿球后都是快速推进的第一选择\n5. 高频挡拆：半场中简单挡拆后快速出手\n6. 放弃进攻篮板：投篮后全员退防（不抢前场板）\n7. 不停奔跑：防守反击+进攻冲刺，消耗对方大个子\n\n【战术效果】\n· 场均得分极高（太阳巅峰期场均110+）\n· 对手大个子球员极度疲惫\n· 比赛节奏快，观赏性强\n\n【战术劣势】\n· 防守端漏洞多\n· 季后赛面对防守强队效果打折扣\n· 需要极高的体能储备\n\n【现代影响】\n跑轰理念深深影响了现代NBA——勇士、火箭的三分狂潮都可追溯到太阳的跑轰革命。', '进攻', 1, 70),

('勇士死亡五小进攻体系', '【战术分类】全队阵地进攻-经典体系\n【代表球队】金州勇士（库里/汤普森/格林/杜兰特时期）\n【教练】史蒂夫·科尔\n\n【战术定义】\n5名球员全部具备三分投射能力和防守换防能力，无限挡拆、换防错位、底角埋伏三分，将进攻空间最大化。没有传统中锋，5人都能处理球、投篮和防守。这是改变NBA打法的革命性战术。\n\n【五大核心要素】\n\n1. 无限空间\n   · 5人全拉开到三分线外\n   · 传统中锋被迫拉出内线\n   · 内线空间为突破敞开大门\n   · 任何人的防守人都不能放空\n\n2. 无限挡拆\n   · 场上5人中任意两人都可以打挡拆\n   · 挡拆后错位：大个防小个的经典错位攻击\n   · 库里-格林挡拆为起手式\n   · 库里的三分威胁让防守必须扑出\n\n3. 底角埋伏\n   · 至少1-2人始终保持在底角\n   · 防守协防路线最远的位置\n   · 汤普森/伊戈达拉经典底角接球\n   · 突破分球的首选目标\n\n4. 小球速度\n   · 5人都能跑，速度压制对方大个\n   · 快攻转换速度极快\n   · 三分快攻（追身三分）作为常规武器\n\n5. 全员传导\n   · 球不停滞，人均触球\n   · 格林高位策应（类似中锋角色）\n   · 多次传导后找到最佳投篮机会\n   · 场均助攻数联盟前列\n\n【战术影响】\n改变了整个NBA的位置定义——传统中锋濒临灭绝，"空间型五号位"成为新标准。', '进攻', 1, 80),

('拉链进攻（Zip Offense）', '【战术分类】全队阵地进攻-经典体系\n\n【战术定义】\n底角球员沿底线或边线，借队友掩护上提高位（罚球线以上区域）接球，以此作为全体系战术的起手式，后续展开挡拆进攻或随机应变。拉链（Zip）形象描述了球员从底角"拉链式"快速移动到高位的路线。\n\n【标准执行流程】\n1. 初始落位：球在弧顶，底角站两人\n2. 底角球员启动：利用内线队友的掩护\n3. 沿边线快速上提（Zip Cut）\n4. 在高位接球，面筐\n5. 接球后的选择：\n   · 直接挡拆：与传球者打Pick and Roll\n   · 突破：利用防守移动中失衡\n   · 传导：继续流转到另一侧\n\n【战术优势】\n· 统一的起手式，后续变化多\n· 利用掩护创造接球空间\n· 可以快速过渡到挡拆体系\n\n【适用场景】\n· 作为半场进攻的第一个战术动作\n· 对手防守注意力集中在持球人时\n· 需要统一的战术发起指令', '进攻', 1, 50),

('连续性轮转进攻（Continuity Offense）', '【战术分类】全队阵地进攻-经典体系\n\n【战术定义】\n固定的循环跑位模式，球员按预设的路线和顺序持续跑动、传球、掩护。一轮跑完如果没有得到好的投篮机会，自动进入下一轮相同的跑位循环，直到出现空位。特别适合业余球队固定训练使用。\n\n【核心特点】\n1. 固定模式：每个球员都知道自己在循环中的角色\n2. 自动循环：不需要教练在场边不断指挥\n3. 人人触球：每个回合每个人都可能接到球\n4. 耐心要求高：可能需要多轮循环才能出机会\n\n【战术优势】\n· 训练简单：固定套路反复练习即可\n· 减少决策负担：球员不需要过多阅读防守\n· 业余球队友好：不依赖超级球星\n· 连续性保证进攻不会停滞\n\n【适用场景】\n· 业余联赛和校园篮球\n· 缺乏明星球员的团队\n· 需要稳定进攻输出的体系', '进攻', 1, 45),

('低位单打体系（重型中锋打法）', '【战术分类】全队阵地进攻-经典体系\n【代表球员】奥尼尔、奥拉朱旺、姚明、恩比德\n\n【战术定义】\n中锋在低位要位接球，其余4名球员全部拉出到外线，清空内线空间。中锋一对一背身单打，利用身高、力量或脚步技术得分。防守包夹时分给外线空位射手。\n\n【执行步骤】\n1. 中锋低位卡位要球\n2. 外围4人拉出三分线外\n3. 球传给低位中锋\n4. 中锋背身单打步骤：\n   · 感知防守人重心\n   · 选择进攻方向（底线或中路）\n   · 利用脚步技术（上下步/翻身跳投/勾手）\n   · 完成得分\n5. 如果遭遇包夹：\n   · 第一时间找到包夹来源方向的空位队友\n   · 外线队友接球后快速传导或投篮\n\n【战术要求】\n· 中锋必须有扎实的低位技术\n· 外线4人必须有稳定的三分能力\n· 中锋面对包夹要有良好的传球视野\n\n【战术演变】\n传统打法在勇士革命后逐渐减少，但季后赛中仍然有效（约基奇/恩比德证明），是"反小球"的重要武器。', '进攻', 1, 70),

('点名单打战术（现代NBA主流）', '【战术分类】全队阵地进攻-经典体系\n【代表事件】2018西部决赛火箭连续点名库里单打\n\n【战术定义】\n通过挡拆换防，故意制造错位：让己方最强得分手面对对方防守最弱的球员进行一对一单打。现代NBA最常用的针对性战术，季后赛尤其高频。\n\n【执行步骤】\n1. 识别目标：找到对方防守最弱的球员（小个后卫或慢脚步大个）\n2. 制造换防：用挡拆让目标球员换防到己方得分手面前\n3. 拉开空间：其他队友拉到球场另一侧，清空单打区域\n4. 一对一单打：利用身体或技术优势得分\n5. 如果协防：分给被放空的队友投三分\n\n【两种点名单打】\n· 点名小个后卫（大个打小个）：利用身高体重优势碾压强吃\n· 点名慢脚步大个（小个打大个）：利用速度优势面筐突破\n\n【战术影响】\n· 迫使对方将防守弱点换下场\n· 改变对方常规轮换\n· 季后赛系列赛中尤其有效\n\n【防守应对】（也体现了战术威力）\n· 被点名球员提前犯规\n· 防守方不换防改为延误回位\n· 被点名球员直接下场\n\n【代表】\n2018西决火箭连续用哈登/保罗挡拆点名库里，迫使勇士调整防守策略。现代篮球中勒布朗·詹姆斯也频繁利用此战术。', '进攻', 1, 75);

-- ============================================
-- 二、防守战术
-- ============================================

-- （一）基础防守配合
INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('关门配合', '【战术分类】基础防守配合\n\n【战术定义】\n两名相邻的防守人在持球突破方向左右同时并拢，像"关门"一样封堵突破路线，迫使持球人停球或回传。\n\n【执行要点】\n1. 持球人突破时，被突破的防守人紧跟不舍\n2. 邻近位置的防守人横向移动补位\n3. 两人在突破路线上形成"门"状封堵\n4. 持球人被迫停球或回传\n5. 关门成功后，两人迅速回到原防守位置\n\n【适用场景】\n· 联防阵型中相邻位置的协防\n· 对方后卫从弧顶突破时\n· 缺乏一对一防守能力时的团队补救\n\n【注意事项】\n· 关门时机要精准，过早会被传球穿透\n· 关门后不要犯规（手部不要下压）\n· 关门形成后一人负责施压一人负责断球', '防守', 1, 60),

('夹击（包夹-双人围堵）', '【战术分类】基础防守配合\n\n【战术定义】\n两名防守人同时上前围堵一名持球人，封住其运球和传球路线，迫使对方仓促出球或失误。分为半场夹击和边线陷阱夹击两种。\n\n【半场夹击执行】\n1. 持球人运球时\n2. 一名防守人上前紧逼\n3. 邻近防守人放弃自己的防守对象\n4. 两人形成包围：一个堵正面，一个堵侧面\n5. 持球人被迫停球或勉强传球\n\n【边线陷阱夹击】\n1. 故意将持球人逼向边线或底角\n2. 边线成为"第三个防守人"\n3. 两人封住两个方向的出球路线\n4. 持球人只剩下向回传或失误两种选择\n\n【注意事项】\n· 夹击时手部要高举，避免犯规\n· 夹击成功后要快速回防原对位人\n· 对方出球后要立即轮转补位\n\n【战术风险】\n· 夹击失败会造成局部4打3\n· 如果对方传球能力强，夹击容易被破解', '防守', 1, 55),

('补防协防', '【战术分类】基础防守配合\n\n【战术定义】\n队友被进攻球员突破后，距离最近的防守人临时放弃自己的防守对象，移动到突破路线进行补防。原防守人快速换防到补防人的防守对象，完成防守阵型的轮转。\n\n【执行流程】\n1. 队友A被进攻球员突破\n2. 邻近队友B看到后立即移动补防\n3. B站到突破路线上堵住进攻\n4. A快速轮转到B原本的防守对象\n5. 形成临时换防\n6. 进攻结束后两人回到原对位\n\n【核心要点】\n· 补防人要喊出来："补了！"让被过的队友知道\n· 轮转速度决定防守质量\n· 补防时机：在进攻人完全过掉队友之前\n\n【团队防守基础】\n补防协防是所有团队防守理念的基础，"帮助队友"是篮球防守的第一原则。', '防守', 1, 50),

('穿过掩护（挤过）', '【战术分类】基础防守配合\n\n【战术定义】\n进攻方设置掩护时，防守人从掩护人和自己的防守对象之间强行挤过去，继续保持对原防守人的紧逼防守。这是一种"不换防"的防守策略。\n\n【执行要点】\n1. 预判掩护即将到来\n2. 提前移动到掩护人的侧面\n3. 从掩护人与持球人之间的缝隙中挤过\n4. 保持与防守对象的身体接触\n5. 挤过后立即恢复防守位置\n\n【技术要求】\n· 防守人需要有良好的敏捷性\n· 提前预判掩护方向\n· 挤过时不能推掩护人（犯规）\n\n【适用场景】\n· 防守对方核心射手（不想换防）\n· 对方掩护人没有投射能力时\n· 防守方有单个顶级防守人时', '防守', 1, 45),

('绕过掩护', '【战术分类】基础防守配合\n\n【战术定义】\n面对掩护时，防守人从掩护人的身后绕过去，重新追赶自己的防守对象。与挤过不同，绕过是"放一步"再追的策略。\n\n【执行要点】\n1. 预判掩护\n2. 主动后撤一步\n3. 从掩护人的身后绕过去\n4. 加速追赶原防守对象\n5. 队友暂时帮忙延误持球人\n\n【优缺点】\n· 优点：不会在掩护上被卡住，减少犯规风险\n· 缺点：给持球人短暂投篮窗口\n\n【适用场景】\n· 对方持球人投篮不准（放投不放突）\n· 防守人身高臂长可以远距离干扰\n· 掩护人身体宽大不易挤过时', '防守', 1, 40),

('换防（Switch）', '【战术分类】基础防守配合\n\n【战术定义】\n挡拆发生时，两名防守人立即互换防守对象，一名防守掩护人，另一名防守持球人。是现代小球时代最高频的防守配合，勇士死亡五小的防守核心。\n\n【执行要点】\n1. 挡拆发生的瞬间\n2. 防守掩护人的球员喊"换！"\n3. 原防守持球人的球员立即换防掩护人\n4. 两人迅速调整防守姿势\n5. 形成新的防守对位\n\n【战术优势】\n· 不给持球人任何投篮或突破空间\n· 执行简单，不易失误\n· 防守阵型不会被掩护打乱\n\n【战术劣势】\n· 可能产生错位（小防大/大防小）\n· 要求5人都能防多个位置\n\n【现代应用】\n无限换防（Switch Everything）：5个位置全部可以换防，是防守的终极形态。勇士、凯尔特人、热火均为代表。', '防守', 1, 70),

('强延误与弱延误（防挡拆专项）', '【战术分类】基础防守配合\n\n【战术定义】\n防守挡拆时，防守掩护人的大个子在挡拆瞬间上提短暂压迫持球人（延误），给原防守人争取回位时间，然后快速回防自己的防守对象。专门用于防守库里、哈登这种顶级挡拆持球人。\n\n【强延误（Hard Hedge）】\n1. 大个子在挡拆瞬间大幅度上提\n2. 短暂双人包夹持球人\n3. 迫使持球人向远离篮筐方向运球\n4. 1-2秒后大个子快速回防自己的对位\n5. 原防守人追回持球人身边\n\n【弱延误（Soft Hedge/Show）】\n1. 大个子稍微上提但不完全压出\n2. 只需露个面让持球人犹豫一下\n3. 立即回防自己的对位\n4. 原防守人几乎没有离开持球人\n\n【战术要点】\n· 大个子的移动速度要快\n· 延误和回位的时机是关键\n· 被延误的持球人往往被迫回传\n\n【适用场景】\n· 对方有超级挡拆持球人（库里/利拉德/东契奇）\n· 不想换防暴露错位时\n· 防守方有大个子移动速度不错的情况', '防守', 1, 55);

-- （二）人盯人防守
INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('半场人盯人防守', '【战术分类】人盯人防守\n\n【战术定义】\n5名防守人各自盯防一名进攻球员，人球兼顾。在己方半场落位后进行人盯人防守。是篮球最基础也是各水平最通用的防守方式。\n\n【防守原则】\n1. 每个人都有明确的防守对象\n2. "人球兼顾"原则：看到球的同时也看到自己防的人\n3. 防守距离根据不同位置调整：\n   · 近篮贴身：离篮越近，防守越紧\n   · 远距放一步：离篮远的持球人可以适当放一步\n4. 防守姿势：屈膝、低重心、侧身、一手干扰一手防突破\n\n【站位要点】\n· 站在对手和篮筐之间\n· 如果是无球防守：站在球和对手之间（阻断传球路线）\n· 防守持球人：一手干扰投篮，一手准备断球\n\n【优缺点】\n· 优点：每个人责任明确，适合业余球队\n· 缺点：一个人被突破整个防守崩溃\n· 缺点：容易被掩护和挡拆破解\n\n【训练要点】\n· 滑步训练是第一基本功\n· 防守意识和反应速度的持续训练\n· 防守沟通（喊话）的重要性', '防守', 1, 75),

('全场紧逼人盯人（FOX紧逼）', '【战术分类】人盯人防守\n\n【战术定义】\n从对方发球线开始，全场任何位置都贴身紧逼自己盯防的球员。利用边线做陷阱，高强度施压迫使对方失误和仓促传球。极具侵略性的防守战术。\n\n【两种主要落位】\n\n1. 1-2-1-1全场紧逼\n   · 第1人（1）：紧逼发球人\n   · 第2人（2）：防守中场接应人\n   · 第3人（1）：防守后场接应人\n   · 第4人（1）：防守篮下（最后防线）\n\n2. 2-2-1全场紧逼\n   · 前场2人：紧逼发球和后场接应\n   · 中场2人：截断中场传球路线\n   · 后场1人：保护篮筐\n\n【边线陷阱】\n· 故意把持球人逼向边线\n· 边线成为第三个防守人\n· 持球人选择受限：被抢断/回传/出界\n\n【适用时机】\n· 比赛关键时刻追分\n· 对方后卫控球能力差\n· 己方体能充沛、板凳深度好\n· 打乱对方比赛节奏\n\n【战术风险】\n· 极大消耗体能\n· 容易被长传破解（后方1防2）\n· 后卫犯规风险增加', '防守', 1, 65);

-- （三）区域联防五大基础阵型
INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('2-3联防（最常用区域防守）', '【战术分类】区域联防\n\n【战术定义】\n2名球员防守弧顶外线区域，3名球员收缩篮下保护内线。全篮球世界最常用的区域联防阵型，护框效果极强。FIBA无防守三秒，所以联防效果比NBA更突出。\n\n【落位详解】\n· 上线2人：分别防守弧顶和两侧45度\n· 下线3人：\n  1. 中间：镇守篮下核心\n  2. 左侧：底线和低位防守\n  3. 右侧：底线和低位防守\n\n【防守覆盖】\n· 强项：内线保护（突破和低位强攻非常困难）\n· 弱项：两侧45度和底角三分可能出现空位\n· 弱项：罚球线中轴区域是人盯人的模糊地带\n\n【适用场景】\n· 对方以内线进攻为主\n· 对方突破型球员多、投射型球员少\n· 己方内线有身高臂展优势\n· 业余比赛最常用阵型\n\n【破解方法】（参见破联防战术）\n· 罚球线站策应点\n· 快速转移球\n· 底角三分', '防守', 1, 75),

('3-2联防（封锁外线）', '【战术分类】区域联防\n\n【战术定义】\n3名球员上线封锁三分线和外线区域，2名球员在篮下保护。是2-3联防的镜像阵型，专门克制外线投射能力强的球队。\n\n【落位详解】\n· 上线3人：弧顶1人+两翼45度各1人\n· 下线2人：分别保护篮筐两侧\n\n【防守覆盖】\n· 强项：外线三分和长两分的压制\n· 强项：防守大量射手的外线大队\n· 弱项：篮下和短距离区域相对空虚\n· 弱项：容易被高吊传球打穿内线\n\n【适用场景】\n· 对方外线三分精准\n· 对方内线威胁较小\n· 需要将防守扩大到三分线外\n\n【破解方法】\n· 2-1-2进攻落位专破3-2联防\n· 内线球员攻击篮下弱点\n· 高位策应后高低位配合', '防守', 1, 60),

('1-3-1联防（均衡阵型）', '【战术分类】区域联防\n\n【战术定义】\n1人弧顶游弋、3人中间一字排开、1人底线保护，形成全区域覆盖。攻防两端最均衡的区域联防阵型，利用横排三人形成的覆盖面制造传球陷阱。\n\n【落位详解】\n· 弧顶1人：全场视野，调度指挥\n· 中部3人横排：从左侧到右侧一字排开\n· 底线1人：保护底线和篮筐\n\n【防守覆盖】\n· 均衡覆盖：几乎所有区域都有人\n· 传球陷阱：中部三人横排容易断传球\n· 弱项：底角三分位置可能轮转不及\n· 弱项：对球员轮转配合要求高\n\n【战术优势】\n· 攻防均衡，不容易出现明显短板\n· 中部三人易于协防和轮转\n· 适合有纪律性的业余球队\n\n【破解方法】\n· 底角三分持续施压\n· 快速转移球调动轮转\n· 1-3-1进攻落位与其镜像对抗', '防守', 1, 55),

('菱形联防（1-2-1）', '【战术分类】区域联防\n\n【战术定义】\n1人弧顶、2人两翼、1人底线，形成菱形（钻石形）站位。侧重两翼（侧翼45度）区域的防守覆盖，适合防守中距离和侧翼进攻为主的球队。\n\n【落位详解】\n· 弧顶1人：防守控球后卫\n· 两翼2人：左右45度区域防守\n· 底线1人：保护篮下\n\n【防守特点】\n· 强项：两翼防守严密\n· 弱项：罚球线和弧顶之间的空间\n· 弱项：左右底角可能出现空位\n\n【适用场景】\n· 对方侧翼进攻能力强\n· 防守中距离投射\n· 业余比赛阵型变化', '防守', 1, 40),

('四角联防', '【战术分类】区域联防\n\n【战术定义】\n4名球员在边线四角站位，1名球员镇守篮下。这是一种混合阵型：4人区域覆盖外围，1人盯住对方核心内线。介于人盯人和区域联防之间的特殊防守。\n\n【落位详解】\n· 四角：球场四个角落各1人\n· 篮下1人：保护篮筐\n\n【防守特点】\n· 强项：外围四点覆盖面广\n· 强项：篮下有专人保护\n· 弱项：中间腹地空旷\n· 弱项：轮转配合复杂\n\n【适用场景】\n· 对方有一个超级内线需要重点照顾\n· 比赛特定回合的变阵\n· 非主流阵型，具有出其不意效果', '防守', 1, 35);

-- （四）特殊防守战术
INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('砍人战术（砍鲨战术 Hack-a-Shaq）', '【战术分类】特殊防守战术\n【战术来源】针对奥尼尔罚球差的弃将战术，唐·尼尔森首创\n\n【战术定义】\n无球阶段主动对对方罚球差的球员犯规，送其上罚球线，赌其罚球命中率低于己方正常攻防效率。由于无球犯规判罚罚球，这是利用规则漏洞的赌博性战术。\n\n【执行要点】\n1. 识别目标：罚球命中率低于50%的球员\n2. 无球阶段果断犯规\n3. 犯规动作要明确（不能是恶意犯规）\n4. 送目标上罚球线\n5. 抢好篮板（大概率罚球不进）\n6. 获得球权后正常进攻\n\n【数据逻辑】\n· 如果对方罚球命中率50%\n· 两次罚球期望得分 = 1分\n· 己方正常进攻期望得分 > 1分\n· 砍人战术就是有利可图的\n\n【NBA规则限制】\n· 第四节最后两分钟砍人：被犯规方获得1罚+球权\n· 这一规则大大削弱了砍人战术的最后一节效果\n\n【适用场景】\n· 对方有罚球黑洞\n· 比赛关键时刻追分\n· 打乱对方进攻节奏', '防守', 1, 60),

('混合联防（盯人+区域混搭）', '【战术分类】特殊防守战术\n\n【战术定义】\n2名防守人对对方核心球星进行人盯人紧逼，剩余3人按区域联防站位。是业余联赛和野球场上最实用的防守战术：既限制了对方最强点，又保护了内线。\n\n【执行方式】\n1. 识别对方两名核心得分手\n2. 派出己方两名最强防守人专职盯防\n3. 其余3人守2-1或1-2区域\n4. 盯人防守者不参与区域轮转\n5. 如果盯人的球员无球，防守人可以适当回收保护\n\n【编排示例】\n· 盯2人+3人2-1联防：双人盯核心球星，三人保护篮下\n· 盯1人+4人1-3联防：单人盯最强点，四人区域\n\n【战术优势】\n· 重点限制对方核心球员\n· 区域保护弥补盯人疏漏\n· 业余球队易于理解和执行\n\n【注意事项】\n· 盯人球员被突破时，区域球员要补防\n· 防守沟通极其重要\n· 盯人和区域球员的切换要流畅', '防守', 1, 50),

('陷阱防守（边线/底角陷阱）', '【战术分类】特殊防守战术\n\n【战术定义】\n有目的地将持球人引导向边线或底角方向，然后在预设好的"陷阱"位置进行突然夹击包夹，利用边线作为第三个防守人迫使对方失误。\n\n【陷阱设置步骤】\n1. 防守人故意站位偏向中路一侧\n2. 诱导持球人向边线或底角方向运球\n3. 持球人进入陷阱区域后\n4. 邻近防守人突然上前形成夹击\n5. 边线/底线成为屏障\n6. 持球人只剩下3个选项：\n   · 回传（防守方抢断机会）\n   · 被迫停球（5秒违例风险）\n   · 被抢断或出界\n\n【陷阱布置位置】\n· 边线陷阱：中场边线两侧\n· 底角陷阱：前场底角\n· 半场线陷阱：过半场瞬间的夹击\n\n【适用场景】\n· 对方控球后卫经验不足\n· 全场紧逼的配套战术\n· 特定回合的预设战术', '防守', 1, 45),

('绕前防守（防低位接球）', '【战术分类】特殊防守战术\n\n【战术定义】\n防守球员站在进攻球员的身体前方，一只手臂后伸感知对手位置，另一只手臂举起干扰传球路线，完全阻断进攻球员的接球路线。是防守强力低位中锋的最有效手段。\n\n【执行要点】\n1. 低位防守人放弃常规的背后防守站位\n2. 移动到进攻球员的前方（绕前）\n3. 一只手向后触摸对手感知位置\n4. 另一只手高举干扰高空传球\n5. 如果对方吊高球：\n   · 弱侧防守人快速协防篮下\n   · 绕前防守人转身追球\n\n【战术效果】\n· 让强力中锋完全接不到球\n· 迫使对方从其他位置发起进攻\n· 心理施压：让内线核心感到沮丧\n\n【战术风险】\n· 背后空虚：一旦吊球成功就是空篮\n· 需要协防球员的配合\n· 体能消耗大\n\n【适用对象】\n· 奥尼尔/姚明/恩比德等重型中锋\n· 低位进攻核心\n· 所有依赖内线得分的情况', '防守', 1, 50);

-- ============================================
-- 三、专门破联防战术
-- ============================================

INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('高位罚球线站人破联防', '【战术分类】破联防战术\n\n【战术定义】\n在罚球线位置放置一名策应能力强的球员（通常是能传能投的大个子），利用这个位置天然位于联防阵型缝隙的特点，吸引防守收缩，创造外线和切入机会。这是破解所有联防阵型的通用法门。\n\n【核心原理】\n· 罚球线是联防体系的"阿喀琉斯之踵"\n· 所有联防阵型的防守注意力都在外围和篮下\n· 罚球线中轴是防守覆盖最弱的位置\n· 在这里接球的球员可以：\n  1. 直接中投（防守来不及扑出）\n  2. 传给空切队友（防线被拉扯出空隙）\n  3. 分外线空位（防守收缩后外线空虚）\n\n【执行步骤】\n1. 弧顶持球人将球传给罚球线队友\n2. 罚球线球员接球后面筐\n3. 防守方必须做出反应：\n   · 如果防守扑出→内线篮下空虚→传底线队友\n   · 如果防守不扑→直接中投\n   · 如果防守轮转→找轮转中的空位队友\n4. 其余4人不停跑动创造接球角度\n\n【针对不同联防】\n· 破2-3联防：罚球线是最佳攻击点\n· 破3-2联防：罚球线+低位配合\n· 破1-3-1联防：罚球线+底角配合\n\n【球员要求】\n· 罚球线球员：良好的中投+传球视野\n· 其他球员：持续的跑动+接球投篮能力', '破联防', 1, 65),

('连续转移球调动联防', '【战术分类】破联防战术\n\n【战术定义】\n通过快速、连续的左右两侧传球，迫使联防阵型不断左右轮转移动。联防的移动永远比球慢，持续的传导最终会创造出防守空位。\n\n【核心原理】\n· 联防的防守是"跟着球走"\n· 球在左侧→左侧5人，右侧空虚\n· 球传到右侧→右侧5人，左侧空虚\n· 但人的移动永远比球慢\n· 连续快速转移就会产生时间差空位\n\n【执行步骤】\n1. 弧顶持球人开始传球\n2. 传到左侧45度→防守重心左移\n3. 左侧立即回传弧顶→防守重心开始回\n4. 弧顶不停球直接传到右侧45度→防守重心来不及\n5. 右侧出现空位投篮机会\n6. 如果防守扑上来→右路突破或再传底角\n\n【传球速度要求】\n· 每一次传球间隔不超过1秒\n· 球不停滞，人不等球\n· 传球线路：弧顶→侧翼→弧顶→对侧→底角\n\n【训练方法】\n· 5人绕三分线快速传球练习\n· 要求每人触球不超过1秒\n· 直到出现空位投篮机会才出手', '破联防', 1, 55),

('底线穿插溜底破联防', '【战术分类】破联防战术\n\n【战术定义】\n无球进攻球员在底线区域（篮筐下方到两侧底角）不断穿插跑动，利用底线区域防守覆盖最薄弱的特性，撕裂联防阵型的底部防线，创造篮下或近距离得分机会。\n\n【战术原理】\n· 联防阵型在底线的防守覆盖天然薄弱\n· 防守的注意力集中在上线和正面\n· 底线跑动出现在防守人视野盲区\n· 反复底线穿插最终会有人"漏掉"\n\n【执行步骤】\n1. 至少1名无球球员在底线活动\n2. 从一侧底角移动到篮下\n3. 利用篮下队友的身体做天然掩护\n4. 溜到另一侧底角或低位\n5. 防守人在跟防过程中容易迷失\n6. 接球后在联防阵型的"背后"得分\n\n【配合要点】\n· 底线跑动球员和弧顶持球人要有眼神交流\n· 篮下的球员可以设置无球掩护\n· 跑动路线变化：直线→突然弧形→反跑\n\n【适用场景】\n· 破2-3联防（底线三人横排有间隙）\n· 破1-3-1联防（底线只有一人）\n· 对方防守注意力集中在正面时', '破联防', 1, 50),

('45度中投+底角三分穿插破联防', '【战术分类】破联防战术\n\n【战术定义】\n针对联防阵型在45度中距离和底角三分两个位置的天然防守漏洞，通过投手落位和快速传导，在这两个区域进行定点投篮攻击。\n\n【联防漏洞分析】\n· 2-3联防漏洞：45度三分和罚球线中投\n· 3-2联防漏洞：篮下和底角\n· 1-3-1联防漏洞：底角三分\n· 所有联防的共同漏洞：快速转移球后的空位\n\n【攻击策略】\n1. 识别当前联防阵型的特定漏洞\n2. 将最好的射手部署在漏洞位置\n3. 通过快速转移球调动防守\n4. 球到达漏洞位置时果断出手\n5. 不进则抢进攻篮板（联防篮板卡位弱）\n\n【典型场景】\n· 破2-3联防：连续弧顶-45度-底角三传\n· 破3-2联防：底角-低位-底角交叉\n· 破1-3-1联防：底角三分定点投射\n\n【球员要求】\n· 需要有稳定的中距离和三分射手\n· 传球质量要高（人到球到）\n· 要有投篮信心', '破联防', 1, 45);

-- ============================================
-- 四、边线球/绝杀特殊战术
-- ============================================

INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('星爆战术（Starburst）', '【战术分类】绝杀战术\n【别名】群星闪耀战术\n\n【战术定义】\n边线发球时，4名进攻球员同时从不同方向四散跑开（如星爆般爆开），造成防守混乱。一名指定球员在混乱中获得接球空间，接到传球后完成绝杀。是最经典的NBA绝杀战术之一。\n\n【执行步骤】\n1. 发球人站在边线\n2. 4名进攻球员聚集在一起\n3. 裁判哨响的瞬间\n4. 4人同时向四个方向全力冲刺\n5. 防守方无法预判谁会接到球\n6. 防守阵型瞬间被打散\n7. 指定球员（通常是最好射手）跑向设计好的接球点\n8. 其他3人的跑动是"烟雾弹"\n9. 发球人传给指定球员\n10. 接球后立即投篮\n\n【战术优势】\n· 防守无法预判（4个潜在目标）\n· 一人接球，另外三人是诱饵\n· 混乱中创造机会\n· 简单直接，不需要复杂配合\n\n【经典案例】\nNBA多次绝杀使用星爆战术，包括雷·阿伦、利拉德等射手青睐此战术。\n\n【注意事项】\n· 发球人有5秒发球限制（NBA/FIBA均适用）\n· 不能发球违例（脚踩线）\n· 接球人需要快速稳定的投篮动作', '绝杀战术', 1, 70),

('电梯门掩护（Elevator Door）', '【战术分类】绝杀战术\n【代表球队】金州勇士\n\n【战术定义】\n两名队友面对面并排站位，之间留出一条通道，射手从两人中间快速穿过，两人在射手通过后迅速合拢（像电梯关门一样），挡住追防的防守人，为射手创造完全空位的投篮机会。\n\n【执行步骤】\n1. 两名大个子球员在三分线附近面对面站立\n2. 两人之间留出约1米的通道\n3. 射手从远处启动\n4. 快速从两人中间的通道穿过\n5. 射手穿过的瞬间：\n   · 两人迅速靠近，将通道"关闭"\n   · 追防的防守人撞上"关闭的门"\n   · 射手获得完全空位\n6. 发球人/持球人将球传给射手\n7. 射手在无人防守下投篮\n\n【战术要点】\n· 关门时机：射手刚穿过就立即合拢\n· 两个掩护人的距离：刚好一个身位\n· 关门要坚决：防守人撞上来就是掩护犯规\n\n【规则合规性】\n· 两人在关门时必须站稳不动\n· 如果关门时移动会被吹非法掩护\n· 因此关门时机是全战术最关键的技术\n\n【经典案例】\n勇士队为库里/汤普森设计的最爱绝杀战术，2015-2019赛季多次使用。', '绝杀战术', 1, 65),

('双掩护绝杀战术', '【战术分类】绝杀战术\n\n【战术定义】\n两名队友并排站定为射手设置双人掩护（Double Screen），射手从远处启动，绕双掩护跑出接球，利用双人掩护的宽度确保完全甩开防守，获得空位投篮机会。\n\n【执行步骤】\n1. 两名掩护人并排站在三分线附近\n2. 两人身体紧贴，形成更宽的掩护面\n3. 射手站在弱侧远处\n4. 发球哨响后射手全速跑动\n5. 从双掩护旁边紧贴绕出\n6. 防守人无论是挤过还是绕过都被挡住\n7. 射手在弧顶或45度获得空位\n8. 接发球后直接投篮\n\n【战术优势】\n· 双人掩护宽度是单掩护的两倍\n· 防守人极难穿过\n· 比电梯门掩护更容易在FIBA规则下合规\n\n【适用场景】\n· 比赛最后时刻需要三分\n· 有出色的绕掩护射手\n· FIBA规则下比电梯门更稳妥', '绝杀战术', 1, 55),

('低位吊篮下绝杀', '【战术分类】绝杀战术\n\n【战术定义】\n边线发球时，一名球员利用队友的掩护突然空切篮下，发球人将球高吊传入篮下，空切球员接球后直接上篮完成绝杀。利用所有人都认为绝杀必然投三分或中投的思维定势。\n\n【执行步骤】\n1. 发球人站在边线\n2. 3名外线球员做出即将接球投三分的假象\n3. 防守注意力全部集中在外线\n4. 1名球员在人群中突然向篮下切入\n5. 借助队友的瞬间掩护甩开防守\n6. 发球人将球高吊传入篮下\n7. 空切球员接球，篮下无人防守\n8. 轻松上篮得分\n\n【战术优势】\n· 反常规思维：绝杀=三分→防守扑出→篮下空虚\n· 简单高效：空篮命中率近100%\n· 出奇制胜\n\n【经典案例】\n2010年湖人vs国王，科比边线发球吊篮下加索尔绝杀。\n\n【注意事项】\n· 吊球高度要防防守人拦截\n· 空切时机要与发球同步\n· 空切球员要有优秀的弹跳和接球能力', '绝杀战术', 1, 60);

-- ============================================
-- 五、攻守转换战术
-- ============================================

INSERT INTO tactic_info (title, content, type, is_published, view_count) VALUES
('防守反击', '【战术分类】攻守转换战术\n\n【战术定义】\n抢断或盖帽的瞬间，全队立即从防守状态切换到进攻状态，所有球员快速向前场冲刺，利用对方还没从进攻心态转换过来的短暂时间差，打出人数优势的快速反击。\n\n【触发条件】\n· 抢断成功 → 立即快攻\n· 盖帽后球权转换 → 快速推进\n· 对方失误 → 抓住转换机会\n\n【执行要点】\n1. 抢断/盖帽瞬间所有人同时启动\n2. 持球人快速推进（运球或传球）\n3. 其余4人全速向前场冲刺\n4. 形成多打少局面\n5. 选择最优终结方式：\n   · 直接上篮（1v0）\n   · 二打一配合（2v1）\n   · 三打二传导（3v2）\n\n【核心原则】\n· 速度第一：第一时间冲刺\n· 果断出手：不犹豫，不等全队落位\n· 阅读防守：根据退防人数选择进攻方式\n\n【训练方法】\n· 全队快速转换练习\n· 抢断后3秒内完成进攻\n· 模拟2v1、3v2快攻场景', '攻守转换', 1, 60),

('快速退防', '【战术分类】攻守转换战术\n\n【战术定义】\n进攻失误（投篮不中、失误、被抢断）后，全队立即转为防守模式，优先收缩篮下保护，防止对方打出快速反击。在退防的同时逐步找到各自的防守对位。\n\n【退防原则】\n1. 丢球瞬间全队立即转身回跑\n2. 退防优先级：\n   · 第一优先：保护篮筐（防止对方直接上篮）\n   · 第二优先：找到持球人（阻止快攻推进）\n   · 第三优先：找到各自对位人\n3. 退防人数要求：\n   · 至少3人第一时间退回半场\n   · 最好5人全部退回\n4. 退防时防守站的位方式：\n   · 收缩篮下→逐步外扩\n   · 阻止三分线内的快速得分\n\n【特殊场景】\n· 后场只有1-2人退防：先堵中路，逼迫对方去边线\n· 对方人数优势：退回到篮下保护，放弃外线防守\n· 己方进攻篮板未抢到：抢篮板的球员留在前场施压\n\n【注意事项】\n· 退防不是消极回跑，是在回跑中建立防守\n· 退防要有沟通（"回来！""右边有快下！"）\n· 现代篮球最容易被忽视的基本功', '攻守转换', 1, 55),

('篮板一传', '【战术分类】攻守转换战术\n\n【战术定义】\n抢到防守篮板后，篮板手在落地的瞬间或落地后第一时间将球传给已经启动的队友，用最快速度将球从后场推进到前场，发动快速反击。这是攻守转换的关键起手式。\n\n【执行步骤】\n1. 对方投篮，全体准备抢防守篮板\n2. 篮板手卡位后抢到篮板\n3. 抢到篮板的瞬间：\n   · 落地时将球高举\n   · 立即寻找前场快下队友\n   · 判断传球路线是否安全\n4. 一传方式选择：\n   · 长传（棒球式肩上传）：快下队友远离防守\n   · 短传（胸前传球）：传给已启动的后卫\n   · 运球推进：没有安全传球路线时自己带球\n5. 快下队友接球后直接攻筐\n\n【战术要素】\n· 篮板手：好的篮板+好的第一传视野\n· 快下人：速度（最先下快攻的1-2人）\n· 一传：关键环节，球速决定快攻速度\n\n【经典组合】\n· 乐福（篮板手）+詹姆斯（快下人）= 骑士经典快攻\n· 约基奇（篮板+长传）+戈登/穆雷（快下）= 掘金现代版本\n\n【注意事项】\n· 一传安全第一：被拦截等于直接送分\n· 没有快下目标且被紧逼时，传给最近的后卫\n· 篮板手不要急着运球，传球永远比运球快', '攻守转换', 1, 60);